#include <bits/stdc++.h>
using namespace std;
int f[5003],n,m,p;
int find(int x){
	if(f[x]==x)return x;
	return f[x]=find(f[x]);
}
void merge(int x,int y){
	int f_x=find(x),f_y=find(y);
	if(f_x!=f_y)f[f_y]=f_x;
}
int main(){
    cin>>n>>m>>p;
    for(int i=1;i<=n;i++)f[i]=i;
    for(int i=1;i<=m;i++){
        int x,y;
        cin>>x>>y;
        merge(x,y);
    }
    for(int i=1;i<=p;i++){
        int x,y;
        cin>>x>>y;
        if(find(x)==find(y))cout<<"Yes\n";
        else cout<<"No\n";
    }
    return 0;
}
